/**
 * StorageAdapter Module
 * Architecture reference: StorageAdapter Module (architecture.md)
 *
 * Abstracts LocalStorage operations with version tracking.
 * IStorage interface enables future Electron (electron-store) swap
 * without touching any consumer code.
 *
 * Electron migration note (DevA申告):
 *   When migrating to Electron, implement IStorage using electron-store
 *   and inject it at app startup. No other files need modification.
 */

import type { Todo } from '@/types/todo'
import { STORAGE_KEYS, CURRENT_STORAGE_VERSION } from '@/types/todo'
import { validateTodoData } from '@/lib/todo/TodoCore'

// ─── Public interface (Electron-swap seam) ────────────────────────────────────

export interface StorageStats {
  used: number
  available: number
  usedPercent: number
}

export interface IStorage {
  initializeStorage(): void
  saveTodos(todos: Todo[]): void
  loadTodos(): Todo[]
  clearAllTodos(): void
  getStorageStats(): StorageStats
}

// ─── LocalStorage implementation ──────────────────────────────────────────────

class LocalStorageAdapter implements IStorage {
  /**
   * Initialize storage schema with version tracking.
   * Creates version key if not present; triggers migration hook if version mismatch.
   */
  initializeStorage(): void {
    try {
      const storedVersion = localStorage.getItem(STORAGE_KEYS.STORAGE_VERSION)

      if (storedVersion === null) {
        // Fresh install
        localStorage.setItem(STORAGE_KEYS.STORAGE_VERSION, CURRENT_STORAGE_VERSION)
        localStorage.setItem(STORAGE_KEYS.TODOS, JSON.stringify([]))
        console.info('[StorageAdapter] Fresh storage initialized:', CURRENT_STORAGE_VERSION)
        return
      }

      if (storedVersion !== CURRENT_STORAGE_VERSION) {
        // Future: call migration function here
        console.warn(
          `[StorageAdapter] Version mismatch: stored=${storedVersion}, current=${CURRENT_STORAGE_VERSION}. Migration may be required.`
        )
      }
    } catch (error) {
      console.error('[StorageAdapter] initializeStorage failed:', error)
    }
  }

  /**
   * Persist todo array to LocalStorage with JSON serialization.
   * Also writes backup for disaster recovery per architecture.md offline guardrail.
   */
  saveTodos(todos: Todo[]): void {
    try {
      const serialized = JSON.stringify(todos)
      localStorage.setItem(STORAGE_KEYS.TODOS, serialized)
      // Backup for disaster recovery
      localStorage.setItem(STORAGE_KEYS.BACKUP, serialized)
    } catch (error) {
      if (error instanceof DOMException && error.name === 'QuotaExceededError') {
        console.error('[StorageAdapter] Storage quota exceeded. Cannot save todos.')
        throw new StorageQuotaError('LocalStorage quota exceeded. Please delete some tasks.')
      }
      throw error
    }
  }

  /**
   * Retrieve complete todo collection from LocalStorage.
   * Falls back to backup key if primary is corrupted.
   * Filters out invalid entries rather than crashing.
   */
  loadTodos(): Todo[] {
    try {
      const raw = localStorage.getItem(STORAGE_KEYS.TODOS)
      if (raw === null) return []

      const parsed: unknown = JSON.parse(raw)
      if (!Array.isArray(parsed)) {
        console.warn('[StorageAdapter] Stored todos is not an array. Attempting backup recovery.')
        return this.loadFromBackup()
      }

      // Validate each item; drop malformed entries
      const valid = parsed.filter((item): item is Todo => {
        if (!validateTodoData(item)) {
          console.warn('[StorageAdapter] Dropping invalid todo entry:', item)
          return false
        }
        return true
      })

      return valid
    } catch {
      console.error('[StorageAdapter] Failed to parse todos. Attempting backup recovery.')
      return this.loadFromBackup()
    }
  }

  /**
   * Clear all todos from both primary and backup keys.
   */
  clearAllTodos(): void {
    localStorage.removeItem(STORAGE_KEYS.TODOS)
    localStorage.removeItem(STORAGE_KEYS.BACKUP)
    localStorage.setItem(STORAGE_KEYS.TODOS, JSON.stringify([]))
  }

  /**
   * Return storage usage statistics.
   * Most browsers cap localStorage at ~5MB.
   */
  getStorageStats(): StorageStats {
    try {
      let used = 0
      for (const key in localStorage) {
        if (Object.prototype.hasOwnProperty.call(localStorage, key)) {
          used += (localStorage.getItem(key) ?? '').length + key.length
        }
      }
      // UTF-16 → bytes (×2), browser limit ~5MB = 5,242,880 bytes
      const usedBytes = used * 2
      const limitBytes = 5 * 1024 * 1024
      const available = Math.max(0, limitBytes - usedBytes)

      return {
        used: usedBytes,
        available,
        usedPercent: Math.min(100, (usedBytes / limitBytes) * 100),
      }
    } catch {
      return { used: 0, available: 5 * 1024 * 1024, usedPercent: 0 }
    }
  }

  // ─── Private helpers ──────────────────────────────────────────────────────

  private loadFromBackup(): Todo[] {
    try {
      const backup = localStorage.getItem(STORAGE_KEYS.BACKUP)
      if (backup === null) return []
      const parsed: unknown = JSON.parse(backup)
      if (!Array.isArray(parsed)) return []
      return parsed.filter((item): item is Todo => validateTodoData(item))
    } catch {
      console.error('[StorageAdapter] Backup recovery also failed. Returning empty array.')
      return []
    }
  }
}

// ─── Custom errors ─────────────────────────────────────────────────────────────

export class StorageQuotaError extends Error {
  constructor(message: string) {
    super(message)
    this.name = 'StorageQuotaError'
  }
}

// ─── Singleton export ──────────────────────────────────────────────────────────

export const storageAdapter: IStorage = new LocalStorageAdapter()
