/**
 * TodoCore Module
 * Architecture reference: TodoCore Module (architecture.md)
 *
 * Pure domain logic — no side effects, no storage, no React.
 * All functions are deterministic and independently testable.
 */

import type { Todo, CreateTodoInput, UpdateTodoInput } from '@/types/todo'

// ─── ID generation ─────────────────────────────────────────────────────────────

/**
 * Timestamp-based UUID per architecture.md spec.
 * Collision probability negligible for single-device, single-user usage.
 */
function generateId(): string {
  return `todo_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`
}

// ─── Core operations ──────────────────────────────────────────────────────────

/**
 * Create a new Todo with validated input.
 * Throws if title is empty or exceeds 100 chars.
 */
export function createTodo(input: CreateTodoInput): Todo {
  const title = input.title.trim()

  if (title.length === 0) {
    throw new TodoValidationError('タイトルを入力してください。')
  }
  if (title.length > 100) {
    throw new TodoValidationError('タイトルは100文字以内で入力してください。')
  }
  if (input.emoji.trim().length === 0) {
    throw new TodoValidationError('絵文字を選択してください。')
  }

  const now = Date.now()

  return {
    id: generateId(),
    title,
    emoji: input.emoji.trim(),
    ...(input.description !== undefined && { description: input.description }),
    ...(input.dueDate !== undefined && { dueDate: input.dueDate }),
    status: 'active',
    createdAt: now,
    updatedAt: now,
  }
}

/**
 * Apply partial updates to an existing Todo, returning a new object.
 * Immutable — does not mutate the original.
 */
export function updateTodo(todo: Todo, updates: UpdateTodoInput): Todo {
  const patch: Partial<Todo> = {}

  if (updates.title !== undefined) {
    const title = updates.title.trim()
    if (title.length === 0) throw new TodoValidationError('タイトルを入力してください。')
    if (title.length > 100) throw new TodoValidationError('タイトルは100文字以内で入力してください。')
    patch.title = title
  }

  if (updates.description !== undefined) patch.description = updates.description
  if (updates.emoji !== undefined) patch.emoji = updates.emoji.trim()
  if (updates.dueDate !== undefined) patch.dueDate = updates.dueDate

  if (updates.status !== undefined) {
    patch.status = updates.status
    if (updates.status === 'completed') {
      patch.completedAt = Date.now()
    } else {
      // un-completing: remove completedAt
      patch.completedAt = undefined
    }
  }

  const updated: Todo = {
    ...todo,
    ...patch,
    updatedAt: Date.now(),
  }

  return updated
}

/**
 * Runtime type guard for Todo.
 * Used by StorageAdapter to validate deserialized data.
 * Architecture requirement: validate before persistence.
 */
export function validateTodoData(data: unknown): data is Todo {
  if (typeof data !== 'object' || data === null) return false

  const d = data as Record<string, unknown>

  return (
    typeof d['id'] === 'string' &&
    d['id'].length > 0 &&
    typeof d['title'] === 'string' &&
    d['title'].length > 0 &&
    typeof d['emoji'] === 'string' &&
    (d['status'] === 'active' || d['status'] === 'completed') &&
    typeof d['createdAt'] === 'number' &&
    typeof d['updatedAt'] === 'number'
  )
}

// ─── Custom errors ─────────────────────────────────────────────────────────────

export class TodoValidationError extends Error {
  constructor(message: string) {
    super(message)
    this.name = 'TodoValidationError'
  }
}
